using UnityEngine;
using UnityEngine.UI;

public class Script {
    public static object Main() {
        var canvasGO = GameObject.Find("Canvas");
        var canvasRT = canvasGO.GetComponent<RectTransform>();
        var screenWidth = canvasRT.sizeDelta.x;
        var screenHeight = canvasRT.sizeDelta.y;
        var buttonHeight = screenHeight / 10f;

        // Buscar strip existente y eliminar
        var existing = GameObject.Find("BottomButtonStrip");
        if (existing != null) Object.Destroy(existing);

        // Crear grupo de botones inferior
        var bottomGO = new GameObject("BottomButtonStrip");
        bottomGO.transform.SetParent(canvasGO.transform);
        var bottomRT = bottomGO.AddComponent<RectTransform>();
        bottomRT.anchorMin = new Vector2(0, 0);
        bottomRT.anchorMax = new Vector2(1, 0);
        bottomRT.pivot = new Vector2(0.5f, 0);
        bottomRT.anchoredPosition = new Vector2(0, buttonHeight / 2f);
        bottomRT.sizeDelta = new Vector2(0, buttonHeight);

        // Crear 3 botones
        for (int i = 0; i < 3; i++) {
            var btnGO = new GameObject($"BottomButton{i+1}");
            btnGO.transform.SetParent(bottomGO.transform);
            var btnRT = btnGO.AddComponent<RectTransform>();

            btnRT.anchorMin = new Vector2(i * 0.333f, 0);
            btnRT.anchorMax = new Vector2((i + 1) * 0.333f, 1);
            btnRT.pivot = new Vector2(0.5f, 0.5f);
            btnRT.anchoredPosition = Vector2.zero;
            btnRT.sizeDelta = Vector2.zero;

            var image = btnGO.AddComponent<Image>();
            image.color = Color.red;

            var button = btnGO.AddComponent<Button>();
            var colors = button.colors;
            colors.normalColor = Color.red;
            colors.highlightedColor = Color.green;
            colors.pressedColor = new Color(0.5f, 0, 0);
            colors.disabledColor = Color.gray;
            colors.colorMultiplier = 1f;
            colors.fadeDuration = 0.1f;
            button.colors = colors;
        }

        return $"Strip inferior creado: 3 botones, {buttonHeight} altura";
    }
}
